94	error_t verify_batch(const base_pke_i& base_pke, curve_id curve, mem_t ek, mem_t ciphertext,
95	                     const std::vector<mem_t>& Qs_compressed, mem_t label) {
96	  if (const error_t rv =
97	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
98	    return rv;
99	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
100	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
101	    return rv;
102	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg(Qs_compressed, "Qs_compressed")) return rv;
103	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
104	  error_t rv = UNINITIALIZED_ERROR;
105	
106	  const auto icurve = to_internal_curve(curve);
107	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
108	
109	  pve_batch_ciphertext_blob_v1_t blob;
110	  if (rv = parse_batch_ciphertext(ciphertext, blob)) return rv;
111	
112	  const int n = static_cast<int>(blob.batch_count);
113	  if (static_cast<size_t>(n) != Qs_compressed.size()) return coinbase::error(E_BADARG, "Q count mismatch");
114	
115	  base_pke_bridge_t bridge(base_pke);
116	  coinbase::mpc::ec_pve_batch_t pve_ct(n);
117	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
118	
119	  for (const auto& q : pve_ct.get_Qs()) {
120	    if (q.get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
121	  }
122	
123	  std::vector<coinbase::crypto::ecc_point_t> Q_expected;
124	  Q_expected.resize(static_cast<size_t>(n));
125	  for (int i = 0; i < n; i++) {
126	    if (rv = Q_expected[static_cast<size_t>(i)].from_bin(icurve, Qs_compressed[static_cast<size_t>(i)]))
127	      return coinbase::error(rv, "invalid Q");
128	    if (rv = icurve.check(Q_expected[static_cast<size_t>(i)])) return coinbase::error(rv, "invalid Q");
129	  }
130	
131	  const coinbase::mem_t ek_mem(ek.data, ek.size);
132	  return pve_ct.verify(bridge, coinbase::mpc::pve_keyref(ek_mem), Q_expected, label);
133	}
