139	error_t decrypt_batch(const base_pke_i& base_pke, curve_id curve, mem_t dk, mem_t ek, mem_t ciphertext, mem_t label,
140	                      std::vector<buf_t>& out_xs) {
141	  if (const error_t rv =
142	          coinbase::api::detail::validate_mem_arg_max_size(dk, "dk", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
143	    return rv;
144	  if (const error_t rv =
145	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
146	    return rv;
147	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
148	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
149	    return rv;
150	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
151	  error_t rv = UNINITIALIZED_ERROR;
152	
153	  const auto icurve = to_internal_curve(curve);
154	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
155	
156	  pve_batch_ciphertext_blob_v1_t blob;
157	  if (rv = parse_batch_ciphertext(ciphertext, blob)) return rv;
158	
159	  const int n = static_cast<int>(blob.batch_count);
160	
161	  base_pke_bridge_t bridge(base_pke);
162	  coinbase::mpc::ec_pve_batch_t pve_ct(n);
163	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
164	
165	  for (const auto& q : pve_ct.get_Qs()) {
166	    if (q.get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
167	  }
168	
169	  const coinbase::mem_t dk_mem(dk.data, dk.size);
170	  const coinbase::mem_t ek_mem(ek.data, ek.size);
171	
172	  std::vector<coinbase::crypto::bn_t> xs_bn;
173	  rv = pve_ct.decrypt(bridge, coinbase::mpc::pve_keyref(dk_mem), coinbase::mpc::pve_keyref(ek_mem), label, icurve,
174	                      xs_bn, /*skip_verify=*/true);
175	  if (rv) {
176	    out_xs.clear();
177	    return rv;
178	  }
179	
180	  std::vector<buf_t> out_local;
181	  out_local.resize(static_cast<size_t>(n));
182	  const int out_len = icurve.order().get_bin_size();
183	  for (int i = 0; i < n; i++) out_local[static_cast<size_t>(i)] = xs_bn[static_cast<size_t>(i)].to_bin(out_len);
184	
185	  out_xs = std::move(out_local);
186	  return SUCCESS;
187	}
