14	class converter_t {
15	 public:
16	  template <typename T>
17	  static int convert_write(const T& src, byte_ptr out) {
18	    converter_t converter(true);
19	    converter.pointer = out;
20	    converter.convert((T&)src);
21	    return converter.offset;
22	  }
23	
24	  explicit converter_t(bool write);
25	  explicit converter_t(byte_ptr out);
26	  explicit converter_t(mem_t src);
27	
28	  bool is_calc_size() const { return !pointer; }
29	  bool is_write() const { return write; }
30	  bool is_error() const { return rv_error != SUCCESS; }
31	  void set_error();
32	  void set_error(error_t rv);
33	  byte_ptr current() const { return pointer + offset; }
34	  bool at_least(int n) const {
35	    // Check for overflow before performing addition
36	    if (n < 0) return false;
37	    if (offset < 0 || offset > size) return false;
38	    if (n > size - offset) return false;
39	    return true;
40	  }
41	  void forward(int n) {
42	    // Check for overflow before performing addition
43	    if (n < 0 || offset < 0 || offset > INT_MAX - n) {
44	      cb_assert(false);
45	      return;
46	    }
47	    offset += n;
48	  }
49	  int get_size() const { return write ? offset : size; }
50	  int get_offset() const { return offset; }
51	
52	  // Maximum number of elements allowed when (de)serializing a std::vector.
53	  static constexpr uint32_t MAX_CONTAINER_ELEMENTS = 1 << 20;
54	  // Maximum value allowed for `convert_len(...)` when deserializing.
55	  //
56	  // `convert_len` is used as a length prefix for buffers and container counts. Bounding it protects against
57	  // attacker-controlled allocations and loops if a malicious peer supplies an oversized length prefix.
58	  static constexpr uint32_t MAX_CONVERT_LEN = 64 * 1024 * 1024;  // 64 MiB
59	
60	  void convert(bool& value);
61	  void convert(uint8_t& value);
62	  void convert(uint16_t& value);
63	  void convert(uint32_t& value);
64	  void convert(uint64_t& value);
65	  void convert(int8_t& value);
66	  void convert(int16_t& value);
67	  void convert(int32_t& value);
68	  void convert(int64_t& value);
69	  void convert(std::string& value);
70	
71	  // void convert_der(buf_t& value);
72	
73	  template <typename FIRST, typename... LAST>
74	  void convert(FIRST& first, LAST&... last) {
75	    convert(first);
76	    if (!is_error()) convert(last...);
77	  }
78	
79	  void convert_len(uint32_t& len);
80	
81	  template <typename T>
82	  void convert(T& value) {
83	    value.convert(*this);
84	  }
85	  template <typename T>
86	  void convert(std::reference_wrapper<T>& value) {
87	    convert(value.get());
88	  }
89	
90	  uint64_t convert_code_type(uint64_t code, uint64_t code2 = 0, uint64_t code3 = 0, uint64_t code4 = 0,
91	                             uint64_t code5 = 0, uint64_t code6 = 0, uint64_t code7 = 0, uint64_t code8 = 0);
92	
93	  template <typename T, size_t size>
94	  void convert(T (&arr)[size]) {
95	    for (size_t i = 0; i < size; ++i) {
96	      convert(arr[i]);
97	    }
98	  }
99	
100	  template <typename T, size_t size>
101	  void convert(std::array<T, size>& arr) {
102	    for (size_t i = 0; i < size; ++i) {
103	      convert(arr[i]);
104	    }
105	  }
106	
107	  template <typename T>
108	  void convert(array_view_t<T>& arr) {
109	    for (int i = 0; i < arr.count; ++i) {
110	      convert(arr.ptr[i]);
111	    }
112	  }
113	
114	  template <typename T>
115	  void convert(std::vector<T>& value) {
116	    if (!write) value.clear();
117	
118	    uint32_t count = (uint32_t)value.size();
119	    convert_len(count);
120	
121	    if (!write) {
122	      if (count > MAX_CONTAINER_ELEMENTS) {
123	        set_error();
124	        return;
125	      }
126	      value.resize(count);
127	    }
128	    for (uint32_t i = 0; i < count && !is_error(); i++) {
129	      convert(value[i]);
130	    }
131	  }
132	
133	  template <typename E>
134	  void convert_enum(E& value) {
135	    uint32_t tmp = uint32_t(value);
136	    convert(tmp);
137	    if (!is_error()) value = E(tmp);
138	  }
139	
140	  template <typename... ARGS>
141	  void convert_flags(ARGS&... args) {
142	    uint64_t buf = 0;
143	    if (is_write()) flags_to_buf(buf, 0, args...);
144	    convert(buf);
145	    if (!is_error() && !is_write()) flags_from_buf(buf, 0, args...);
146	  }
147	
148	  template <typename TKey, typename TItem, typename TInst>
149	  void convert_with_instance(std::map<TKey, TItem>& value, const TInst& instance) {
150	    if (!write) value.clear();
151	    uint32_t count = (uint32_t)value.size();
152	    convert_len(count);
153	    if (!write) {
154	      if (count > MAX_CONTAINER_ELEMENTS) {
155	        set_error();
156	        return;
157	      }
158	    }
159	    auto v = value.begin();
160	    for (uint32_t i = 0; i < count && !is_error(); i++) {
161	      if (write) {
162	        TKey key = v->first;
163	        convert(key);
164	        convert(v->second);
165	        v++;
166	      } else {
167	        TKey key;
168	        convert(key);
169	        if (is_error()) return;
170	        auto [ref, is_new] = value.emplace(key, instance);
171	        if (!is_new) {
172	          set_error();
173	          return;
174	        }
175	        convert(ref->second);
176	        if (is_error()) return;
177	      }
178	    }
179	  }
180	
181	  template <typename TKey, typename TItem>
182	  void convert(std::map<TKey, TItem>& value) {
183	    convert_with_instance<TKey, TItem, TItem>(value, TItem());
184	  }
185	
186	  void convert(std::vector<bool>& value);
187	  error_t get_rv() const { return rv_error; }
188	  static bool is_code_type(mem_t bin, uint64_t code_type) {
189	    return (bin.size >= 8) && (coinbase::be_get_8(bin.data) == code_type);
190	  }
191	
192	  template <typename... T, size_t... I>
193	  void convert_helper(std::tuple<T...>& tuple, std::index_sequence<I...>) {
194	    convert(std::get<I>(tuple)...);
195	  }
196	  template <typename... T>
197	  void convert(std::tuple<T...>& tuple) {
198	    convert_helper(tuple, std::index_sequence_for<T...>{});
199	  }
200	
201	  template <typename T1, typename T2>
202	  void convert(std::pair<T1, T2>& pair) {
203	    convert(pair.first, pair.second);
204	  }
