206	 protected:
207	  error_t rv_error = SUCCESS;
208	  bool write;
209	  byte_ptr pointer;
210	  int offset, size;
211	
212	 private:
213	  static void flags_to_buf(uint64_t& buf, int offset) {}
214	
215	  void flags_from_buf(uint64_t& buf, int offset) {
216	    if ((buf >> offset) != 0) set_error();
217	  }
218	
219	  template <typename FIRST, typename... LAST>
220	  static void flags_to_buf(uint64_t& buf, int offset, FIRST& first, LAST&... last) {
221	    cb_assert(offset >= 0 && offset < 64);
222	    if (first) buf |= uint64_t(1) << offset;
223	    flags_to_buf(buf, offset + 1, last...);
224	  }
225	
226	  template <typename FIRST, typename... LAST>
227	  void flags_from_buf(uint64_t& buf, int offset, FIRST& first, LAST&... last) {
228	    cb_assert(offset >= 0 && offset < 64);
229	    first = ((buf >> offset) & 1) != 0;
230	    flags_from_buf(buf, offset + 1, last...);
231	  }
232	};
