253	template <typename... ARGS>
254	error_t deser(mem_t bin, ARGS&... args) {
255	  converter_t converter(bin);
256	  converter.convert(args...);
257	  error_t rv = converter.get_rv();
258	  if (rv != SUCCESS) return rv;
259	
260	  // Strict deserialization: reject trailing bytes
261	  if (converter.get_offset() != converter.get_size()) {
262	    return coinbase::error(E_BADARG);
263	  }
264	
265	  return SUCCESS;
266	}
