536	error_t bn_t::vector_from_bin(mem_t mem, int n, int size, const mod_t& q, std::vector<bn_t>& out) {  // static
537	  if (n < 0) return coinbase::error(E_BADARG, "vector_from_bin: negative n", /*to_print_stack_trace=*/false);
538	  if (size < 0)
539	    return coinbase::error(E_BADARG, "vector_from_bin: negative element size", /*to_print_stack_trace=*/false);
540	  if (mem.size < 0)
541	    return coinbase::error(E_BADARG, "vector_from_bin: negative input size", /*to_print_stack_trace=*/false);
542	
543	  const int64_t expected_size = static_cast<int64_t>(n) * static_cast<int64_t>(size);
544	  if (expected_size != static_cast<int64_t>(mem.size))
545	    return coinbase::error(E_BADARG, "vector_from_bin: input size mismatch", /*to_print_stack_trace=*/false);
546	
547	  out.resize(n);
548	  for (int i = 0; i < n; i++, mem = mem.skip(size)) out[i] = bn_t::from_bin(mem.take(size)) % q;
549	  return SUCCESS;
550	}
