555	  if (mem.size == 0) return from_bin(mem);
556	  int unused_bits = bytes_to_bits(mem.size) - bits;
557	  byte_t mask = 0xff >> unused_bits;
558	  if (mem[0] == (mem[0] & mask)) return from_bin(mem);
