56	// Generic adapter that turns any KEM policy into a PVE base PKE via kem_aead_ciphertext_t
57	template <class KEM_POLICY>
58	struct kem_pve_base_pke_t : public pve_base_pke_i {
59	  using EK = typename KEM_POLICY::ek_t;
60	  using DK = typename KEM_POLICY::dk_t;
61	  using CT = crypto::kem_aead_ciphertext_t<KEM_POLICY>;
62	
63	  error_t encrypt(pve_keyref_t ek, mem_t label, mem_t plain, mem_t rho, buf_t& out_ct) const override {
64	    const EK* pub_key = ek.get<EK>();
65	    if (!pub_key) return coinbase::error(E_BADARG, "invalid encryption key");
66	    crypto::drbg_aes_ctr_t drbg(rho);
67	    CT ct;
68	    error_t rv = ct.encrypt(*pub_key, label, plain, &drbg);
69	    if (rv) return rv;
70	    out_ct = ser(ct);
71	    return SUCCESS;
72	  }
73	
74	  error_t decrypt(pve_keyref_t dk, mem_t label, mem_t ct_ser, buf_t& out_plain) const override {
75	    const DK* prv_key = dk.get<DK>();
76	    if (!prv_key) return coinbase::error(E_BADARG, "invalid decryption key");
77	    error_t rv = UNINITIALIZED_ERROR;
78	    CT ct;
79	    if (rv = deser(ct_ser, ct)) return rv;
80	    return ct.decrypt(*prv_key, label, out_plain);
81	  }
82	};
