95	// ---------------------------------------------------------------------------
96	// Runtime / callback-based KEM adapters (for HSM / FFI / wrappers)
97	// ---------------------------------------------------------------------------
98	
99	// Generic runtime KEM callbacks. Intended for wrappers that want to provide a
100	// custom KEM but still reuse cbmpc's KEM/DEM transform (kem_aead_ciphertext_t).
101	//
102	// Requirements:
103	// - `encap` MUST be deterministic given `rho32`.
104	// - `decap` MUST return the same shared secret produced by `encap`.
105	struct pve_runtime_kem_callbacks_t {
106	  using encap_fn_t = error_t (*)(void* ctx, mem_t ek_bytes, mem_t rho32, buf_t& kem_ct, buf_t& kem_ss);
107	  using decap_fn_t = error_t (*)(void* ctx, const void* dk_handle, mem_t kem_ct, buf_t& kem_ss);
108	
109	  void* ctx = nullptr;
110	  encap_fn_t encap = nullptr;
111	  decap_fn_t decap = nullptr;
112	};
113	
114	struct pve_runtime_kem_ek_t {
115	  mem_t ek_bytes;
116	  const pve_runtime_kem_callbacks_t* callbacks = nullptr;
117	};
118	
119	struct pve_runtime_kem_dk_t {
120	  const void* dk_handle = nullptr;
121	  const pve_runtime_kem_callbacks_t* callbacks = nullptr;
122	};
123	
124	struct kem_policy_runtime_kem_t {
125	  using ek_t = pve_runtime_kem_ek_t;
126	  using dk_t = pve_runtime_kem_dk_t;
127	
128	  static error_t encapsulate(const ek_t& pub_key, buf_t& kem_ct, buf_t& kem_ss, crypto::drbg_aes_ctr_t* drbg) {
129	    if (!pub_key.callbacks || !pub_key.callbacks->encap) return E_BADARG;
130	    constexpr int rho_size = 32;
131	    buf_t rho = drbg ? drbg->gen(rho_size) : crypto::gen_random(rho_size);
132	    return pub_key.callbacks->encap(pub_key.callbacks->ctx, pub_key.ek_bytes, rho, kem_ct, kem_ss);
133	  }
134	
135	  static error_t decapsulate(const dk_t& prv_key, mem_t kem_ct, buf_t& kem_ss) {
136	    if (!prv_key.callbacks || !prv_key.callbacks->decap) return E_BADARG;
137	    return prv_key.callbacks->decap(prv_key.callbacks->ctx, prv_key.dk_handle, kem_ct, kem_ss);
138	  }
139	};
