143	// HSM-backed decapsulation for the built-in RSA-OAEP KEM.
144	//
145	// The callback must perform RSA-OAEP decryption (OAEP label is empty per our KEM policy)
146	// and return the recovered KEM shared secret.
147	struct pve_rsa_oaep_hsm_dk_t {
148	  using decap_fn_t = error_t (*)(void* ctx, mem_t dk_handle, mem_t kem_ct, buf_t& kem_ss);
149	
150	  mem_t dk_handle;
151	  void* ctx = nullptr;
152	  decap_fn_t decap = nullptr;
153	};
154	
155	struct kem_policy_rsa_oaep_hsm_t {
156	  using ek_t = crypto::rsa_pub_key_t;
157	  using dk_t = pve_rsa_oaep_hsm_dk_t;
158	
159	  static error_t encapsulate(const ek_t& pub_key, buf_t& kem_ct, buf_t& kem_ss, crypto::drbg_aes_ctr_t* drbg) {
160	    return crypto::kem_policy_rsa_oaep_t::encapsulate(pub_key, kem_ct, kem_ss, drbg);
161	  }
162	
163	  static error_t decapsulate(const dk_t& prv_key, mem_t kem_ct, buf_t& kem_ss) {
164	    if (!prv_key.decap) return E_BADARG;
165	    error_t rv = prv_key.decap(prv_key.ctx, prv_key.dk_handle, kem_ct, kem_ss);
166	    if (rv) return rv;
167	
168	    // Our RSA-OAEP KEM policy uses a 32-byte shared secret (SHA-256 output size).
169	    const int expected_ss_size = crypto::hash_alg_t::get(crypto::hash_e::sha256).size;
170	    if (kem_ss.size() != expected_ss_size) return coinbase::error(E_CRYPTO, "invalid RSA KEM output size");
171	
172	    return SUCCESS;
173	  }
174	};
175	
176	inline const pve_base_pke_i& pve_base_pke_rsa_oaep_hsm() { return kem_pve_base_pke<kem_policy_rsa_oaep_hsm_t>(); }
