178	// HSM-backed decapsulation for the built-in ECIES(P-256) KEM.
179	//
180	// The callback only needs to perform the ECDH step and return the raw affine-X
181	// coordinate as a 32-byte big-endian buffer. The library derives the final KEM
182	// shared secret per RFC 9180 (DHKEM(P-256, HKDF-SHA256)).
183	struct pve_ecies_p256_hsm_dk_t {
184	  using ecdh_fn_t = error_t (*)(void* ctx, mem_t dk_handle, mem_t kem_ct, buf_t& dh_x32);
185	
186	  mem_t dk_handle;
187	  void* ctx = nullptr;
188	  ecdh_fn_t ecdh = nullptr;
189	
190	  // Uncompressed public key octets (for kem_context = enc || pub_key).
191	  buf_t pub_key_oct;
192	};
193	
194	struct kem_policy_ecdh_p256_hsm_t {
195	  using ek_t = crypto::ecc_pub_key_t;
196	  using dk_t = pve_ecies_p256_hsm_dk_t;
197	
198	  static error_t encapsulate(const ek_t& pub_key, buf_t& kem_ct, buf_t& kem_ss, crypto::drbg_aes_ctr_t* drbg) {
199	    return crypto::kem_policy_ecdh_p256_t::encapsulate(pub_key, kem_ct, kem_ss, drbg);
200	  }
201	
202	  static error_t decapsulate(const dk_t& prv_key, mem_t kem_ct, buf_t& kem_ss) {
203	    error_t rv = UNINITIALIZED_ERROR;
204	    if (!prv_key.ecdh) return E_BADARG;
205	    if (prv_key.pub_key_oct.empty()) return coinbase::error(E_BADARG, "missing ECIES public key");
206	
207	    crypto::ecc_point_t E;
208	    if (rv = E.from_oct(crypto::curve_p256, kem_ct)) return rv;
209	    if (rv = crypto::curve_p256.check(E)) return rv;
210	
211	    buf_t dh;
212	    if (rv = prv_key.ecdh(prv_key.ctx, prv_key.dk_handle, kem_ct, dh)) return rv;
213	    if (dh.size() != 32) return coinbase::error(E_CRYPTO, "invalid ECDH output size");
214	
215	    // kem_context = enc || pub_key
216	    buf_t kem_context;
217	    kem_context += kem_ct;
218	    kem_context += prv_key.pub_key_oct;
219	
220	    buf_t eae_prk = crypto::kem_policy_ecdh_p256_t::labeled_extract(mem_t("eae_prk"), dh, mem_t());
221	    kem_ss = crypto::kem_policy_ecdh_p256_t::labeled_expand(eae_prk, mem_t("shared_secret"), kem_context, 32);
222	    return SUCCESS;
223	  }
224	};
