228	/**
229	 * @notes:
230	 * - This is the underlying encryption used in PVE
231	 */
232	template <class HPKE_T>
233	buf_t pve_base_encrypt(const typename HPKE_T::ek_t& pub_key, mem_t label, const buf_t& plaintext, mem_t rho) {
234	  crypto::drbg_aes_ctr_t drbg(rho);
235	  typename HPKE_T::ct_t ct;
236	  ct.encrypt(pub_key, label, plaintext, &drbg);
237	  return ser(ct);
238	}
239	
240	/**
241	 * @notes:
242	 * - This is the underlying decryption used in PVE
243	 */
244	template <class HPKE_T>
245	error_t pve_base_decrypt(const typename HPKE_T::dk_t& prv_key, mem_t label, mem_t ciphertext, buf_t& plain) {
246	  error_t rv = UNINITIALIZED_ERROR;
247	  typename HPKE_T::ct_t ct;
248	  if (rv = deser(ciphertext, ct)) return rv;
249	  if (rv = ct.decrypt(prv_key, label, plain)) return rv;
250	  return SUCCESS;
251	}
