18	cbmpc_error_t cbmpc_pve_batch_encrypt(const cbmpc_pve_base_pke_t* base_pke, cbmpc_curve_id_t curve, cmem_t ek,
19	                                      cmem_t label, cmems_t xs, cmem_t* out_ciphertext) {
20	  try {
21	    if (!out_ciphertext) return E_BADARG;
22	    *out_ciphertext = cmem_t{nullptr, 0};
23	
24	    const auto vek = validate_cmem(ek);
25	    if (vek) return vek;
26	    const auto vl = validate_cmem(label);
27	    if (vl) return vl;
28	
29	    std::vector<coinbase::mem_t> xs_cpp;
30	    const auto vxs = view_cmems(xs, xs_cpp);
31	    if (vxs) return vxs;
32	
33	    coinbase::api::curve_id curve_cpp;
34	    const auto cconv = to_cpp_curve(curve, curve_cpp);
35	    if (cconv) return cconv;
36	
37	    coinbase::buf_t ct;
38	    coinbase::error_t rv = UNINITIALIZED_ERROR;
39	    if (base_pke) {
40	      c_base_pke_adapter_t adapter(base_pke);
41	      rv = coinbase::api::pve::encrypt_batch(adapter, curve_cpp, view_cmem(ek), view_cmem(label), xs_cpp, ct);
42	    } else {
43	      rv = coinbase::api::pve::encrypt_batch(curve_cpp, view_cmem(ek), view_cmem(label), xs_cpp, ct);
44	    }
45	    if (rv) return rv;
46	
47	    return alloc_cmem_from_buf(ct, out_ciphertext);
48	  } catch (const std::bad_alloc&) {
49	    if (out_ciphertext) *out_ciphertext = cmem_t{nullptr, 0};
50	    return E_INSUFFICIENT;
51	  } catch (...) {
52	    if (out_ciphertext) *out_ciphertext = cmem_t{nullptr, 0};
53	    return E_GENERAL;
54	  }
55	}
